#include <bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) make_pair(x,y)
#define ull unsigned long long
#define inf 0x3f3f3f3f
#define NoAns puts("-1")
using namespace std;
inline ll read()
{
	ll x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
CI MAXN = 1e6 + 5;
ll n, m, k, a[MAXN], c[MAXN], sum = 0;

int main(void)
{
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
	m = read(), n = read(), k = read();
	a[1] = read();
	++c[1];
	if(a[1]+1<=k)--c[a[1] + 1];
	for (int i = 2; i <= n; ++i)
	{
		a[i] = read();
		ll cnt =( a[i] - a[i - 1] )/ 2;
		if (a[i] - a[i - 1] == 1)continue;
		c[1] += 2;
		if (cnt > k)continue;
		if ((a[i] - a[i - 1] )% 2)
		{
			c[cnt + 1] -= 2;
		}
		else
		{
			--c[cnt], --c[cnt + 1];
		}
	}
	++c[1];
	if(m - a[n] + 1<=k)--c[m - a[n] + 1];
	for (int i = 1; i <= n && k; ++i)
	{
		puts("0");
		--k;
	}
	for (int i = 1; k; ++i)
	{
		sum += c[i];
		for (int j = 1; j <= sum && k; ++j)
		{
			--k;
			write(i);
			puts("");
		}
	}
	return false;
}
